class SearchPage extends StatefulWidget {
  @override
  State<StatefulWidget> createState() => _SearchPageState();
}

class _SearchPageState extends State<SearchPage> {
  final _searchFocusNode = FocusNode();

  @override
  Widget build(BuildContext context) {
    return CupertinoPageScaffold(
      navigationBar: CupertinoNavigationBar(
        middle: CupertinoTextField(
          onSubmitted: (_) => _showDummyPage(context),
          focusNode: _searchFocusNode,
        ),
      ),
      child: SizedBox.shrink(),
    );
  }

  void _showDummyPage(final BuildContext context) {
    Navigator.of(context).push(
      CupertinoPageRoute(
        builder: (context) {
          return CupertinoPageScaffold(
            child: SizedBox.shrink(),
            navigationBar: CupertinoNavigationBar(),
          );
        },
      ),
    );
  }
}
```
3. Run the app on device
4. Write something in the textfield in the navigation bar
5. Submit the text (which navigates to a new page)
6. Navigate back via the back button in the navigation bar
7. Click into the textfield again

**Expected results:** Keyboard pops up and the user can edit the text in the textfield.

**Actual results:** Keyboard does not appear.

